content:
[workspace]
resolver = "2"
members = [
    "dependencies/xapi",
    "xcore",
    "xmodules/*",
    "arceos/modules/*",
    "arceos/crates/*",
]
exclude = [
    "apps",
    "arceos/modules/axdisplay",
    "arceos/modules/axdma",
    "arceos/crates/axdriver_crates",
    "arceos/crates/axdriver_crates/*",
    "arceos/crates/page_table_multiarch",
    "arceos/crates/page_table_multiarch/*",
    "arceos/crates/lwext4_rust",
    "arceos/crates/smoltcp",
    "vendor/axconfig-gen-0.2.1",
    # vDSO source crate targets *-unknown-none with a custom linker script
    # and `dynamic-linking = true` to produce `cdylib`. Built out-of-band
    # by `make regenerate-vdso-blobs`; the resulting `.so` is committed
    # under `xcore/src/vdso/blobs/` and embedded into the kernel via
    # `.incbin`.
    "xmodules/xvdso",
]

[workspace.package]
version = "0.1.0"
edition = "2024"
authors = [
    "Azure-stars <Azure_stars@126.com>",
    "Yuekai Jia <equation618@gmail.com>",
    "Anekoique <anekoique@gmail.com>",
]
license = "GPL-3.0-or-later OR Apache-2.0 OR MulanPSL-2.0"
homepage = "https://github.com/kurohaw/os-kernel-contest"
repository = "https://github.com/kurohaw/os-kernel-contest"
keywords = ["arceos", "kernel"]
categories = ["os", "no-std"]

[workspace.dependencies]
# ----- ArceOS modules ----------------------------------------------------------
axfeat     = { path = "arceos/modules/axfeat", features = ["fs", "irq", "multitask", "net", "smp", "sched_rr"] }
axconfig   = { path = "arceos/modules/axconfig" }
axdisplay  = { path = "arceos/modules/axdisplay" }
axdriver   = { path = "arceos/modules/axdriver" }
axdma      = { path = "arceos/modules/axdma" }
axhal      = { path = "arceos/modules/axhal", features = ["uspace", "rtc", "irq"] }
axlog      = { path = "arceos/modules/axlog" }
axmm       = { path = "arceos/modules/axmm", features = ["cow", "copy-from"] }
axnet      = { path = "arceos/modules/axnet" }
axns       = { path = "arceos/modules/axns", features = ["thread-local"] }
axruntime  = { path = "arceos/modules/axruntime" }
axsync     = { path = "arceos/modules/axsync", features = ["multitask"] }
axtask     = { path = "arceos/modules/axtask", features = ["smp"] }
axalloc    = { path = "arceos/modules/axalloc" }
axfs-ng    = { path = "arceos/modules/axfs-ng", default-features = false, features = ["fat", "thread-local"] }

# ----- Vendored crates (under arceos/crates/) ---------------------------------
allocator            = { path = "arceos/crates/allocator" }
axerrno              = { path = "arceos/crates/axerrno" }
axdriver_base        = { path = "arceos/crates/axdriver_crates/axdriver_base" }
axdriver_block       = { path = "arceos/crates/axdriver_crates/axdriver_block" }
axdriver_display     = { path = "arceos/crates/axdriver_crates/axdriver_display" }
axdriver_net         = { path = "arceos/crates/axdriver_crates/axdriver_net" }
axdriver_pci         = { path = "arceos/crates/axdriver_crates/axdriver_pci" }
axdriver_virtio      = { path = "arceos/crates/axdriver_crates/axdriver_virtio" }
axfs-ng-vfs          = { path = "arceos/crates/axfs-ng-vfs" }
axio                 = { path = "arceos/crates/axio" }
axsched              = { path = "arceos/crates/axsched" }
kernel-elf-parser    = { path = "arceos/crates/kernel_elf_parser" }
lwext4_rust          = { path = "arceos/crates/lwext4_rust", default-features = false }
page_table_entry     = { path = "arceos/crates/page_table_multiarch/page_table_entry" }
page_table_multiarch = { path = "arceos/crates/page_table_multiarch/page_table_multiarch" }
smoltcp              = { path = "arceos/crates/smoltcp", default-features = false }
weak-map             = { path = "arceos/crates/weak-map" }

# ----- SWTC LoongArch modules --------------------------------------------------
xapi     = { path = "dependencies/xapi" }
xcore    = { path = "xcore" }
xcache   = { path = "xmodules/xcache" }
xprocess = { path = "xmodules/xprocess" }
xsignal  = { path = "xmodules/xsignal" }
xuspace  = { path = "xmodules/xuspace" }
xutils   = { path = "xmodules/xutils" }
xvma     = { path = "xmodules/xvma" }

# ----- crates.io --------------------------------------------------------------
bitflags              = "2.6"
cfg-if                = "1.0"
crate_interface       = "0.3"
inherit-methods-macro = "0.1.0"
kernel_guard          = "0.2"
kspin                 = "0.2"
lazyinit              = "0.2"
linkme                = "0.3"
linux-raw-sys = { version = "0.12.1", default-features = false, features = [
    "no_std",
    "general",
    "net",
    "prctl",
    "system",
    "loop_device",
] }
log         = "0.4"
memory_addr = "0.4"
memory_set  = { path = "vendor/memory_set-0.4.1" }
percpu      = "0.4"
rand        = { version = "0.10", default-features = false }
spin        = "0.10"

[package]
name = "swtc_la"
version.workspace = true
edition.workspace = true
authors.workspace = true
homepage.workspace = true
repository.workspace = true

[features]
lwext4_rs = ["axfeat/lwext4_rs"]
# When set, src/main.rs embeds src/test.sh instead of src/init.sh.
# Driven by the top-level ROOT_FEATURES Make variable (see scripts/make/cargo.mk).
init-test = []

[dependencies]
axfeat.workspace = true

axconfig.workspace  = true
axdriver.workspace  = true
axfs-ng.workspace   = true
axhal.workspace     = true
axlog.workspace     = true
axruntime.workspace = true
axsync.workspace    = true
axtask.workspace    = true
axmm.workspace      = true
axio.workspace      = true

xprocess.workspace = true
xsignal.workspace  = true
xuspace.workspace  = true
xvma.workspace     = true
xcache.workspace   = true

axerrno.workspace               = true
inherit-methods-macro.workspace = true
linkme.workspace                = true
linux-raw-sys.workspace         = true

xcore.workspace  = true
xapi.workspace   = true
xutils.workspace = true

spin.workspace = true
shlex    = { version = "1.3.0", default-features = false }
syscalls = { git = "https://github.com/jasonwhite/syscalls.git", rev = "92624de", default-features = false }

[patch.crates-io]
axerrno = { path = "arceos/crates/axerrno" }

//! The main module and entrypoint

#![deny(missing_docs)]
#![no_std]
#![no_main]
#![feature(build_hasher_simple_hash_one)]
#![feature(panic_info_message)]
#![feature(alloc_error_handler)]
#![feature(negative_impls)]
#![feature(sync_unsafe_cell)]
#![feature(linked_list_remove)]
#![feature(core_intrinsics)]
#![feature(const_mut_refs)]
#![feature(let_chains)]
#![feature(once_cell)]
#![allow(incomplete_features)]
#![feature(trait_upcasting)]

extern crate alloc;
// extern crate intrusive_collections;

#[macro_use]
extern crate bitflags;

#[path = "boards/mod.rs"]
mod board;

mod config;
#[macro_use]
mod driver;
mod executor;
mod fs;
mod loader;
mod mm;
mod net;
mod oscomp;
mod panic;
mod process;
mod processor;
mod signal;
///
mod sync;
mod syscall;
mod timer;
mod trap;
mod utils;

use core::{
    arch::{asm, global_asm},
    sync::atomic::{AtomicBool, Ordering},

#![no_std]
#![no_main]
#![doc = include_str!("../README.md")]

#[macro_use]
extern crate axlog;
extern crate alloc;
extern crate axruntime;

use alloc::{format, string::ToString};

mod entry;
mod mm;
mod syscall;

const LOGO: &str = r#"
  SWTC Operating System
  LoongArch evaluation kernel
"#;

fn print_logo() {
    ax_println!("{}", LOGO);
}

#[unsafe(no_mangle)]
fn main() {
    print_logo();
    xprocess::Process::new_init(axtask::current().id().as_u64() as _).build();
    xcore::fs::vfs::init_root().expect("Failed to mount vfs");
    xcore::fs::fd::init_stdio().expect("Failed to init stdio");

    let envs = [format!("ARCH={}", option_env!("ARCH").unwrap_or("unknown"))];

    #[cfg(feature = "init-test")]
    let init = include_str!("test.sh");
    #[cfg(not(feature = "init-test"))]
    let init = include_str!("init.sh");

    info!("Running init script");
    let args = ["/musl/busybox", "sh", "-c", init]
        .map(|s| s.to_string())
        .to_vec();
    let exit_code = entry::run_user_app(&args, &envs);
    info!("Init script exited with code: {:?}", exit_code);
    axhal::misc::terminate();
}
